INSERT INTO `sekolah_fasilitastik` (`id`, `sekolah_id`, `listrik_status`, `listrik_sumber`, `listrik_durasi`, `jumlah_kom`, `labkom_status`, `internet_status`, `internet_sumber`, `internet_bandwith`, `topologi_jaringan`, `internet_kesesuaian`, `internet_alasankuota`, `saran_pengembangan`, `created_at`, `updated_at`) VALUES
(3, 94, 'ada', 'PLN', '24', '33', 'ada', 'ada', 'Indihome', '50', 'LAN', 'Sesuai', NULL, 'MOHON PENAMBAHAN KOMPUTER/PC', '2025-11-02 22:54:49', '2025-11-02 22:54:49'),
(4, 75, 'ada', 'PLN', '24', '25', 'tidak', 'ada', 'Indihome', '50', 'Wireless', 'Tidak Sesuai', 'KETERBATASAN WIFI  DAN JARINGAN YANG TIDAK STABIL', '1. Mohon adanya pelatihan berbasis TPACK kepada para guru untuk kurikulum deep learning yang fokusnya mengganti pelatihan   TIK umum menjadi pelatihan yang berfokus pada integrasi TIK kedalam pedagogik konten hingga sampai kepada bagaimana pemanfaatan rumah pendidikan platform ruang GTK yang benar benar dimanfaatkan dengan baik bagi seluruh dewan guru.\r\n 2. Mohon adanya program pelatihan guru master trainer daerah yang berfokus membentuk tim inti Guru TIK (Coaching) ataupun pelatihan guru program pembelajaran koding dan KA untuk menjadi mentor bagi guru di masing masing satuan pendidikan. setelah pelatihan dilakukan juga pendampingan agar koding ataupun pembelajaran berbasis TIK ini bisa bermanfaat bagi banyak guru maupun siswa. \r\n3.  Mohon adanya bantuan dari Dinas mengenai Sarana dan Prasarana IT untuk kelancaran Proses BELAJAR mengajar dikelas.', '2025-11-03 00:20:30', '2025-11-04 20:16:33'),
(5, 52, 'ada', 'PLN', '24', '0', 'tidak', 'ada', 'Indihome', '30', 'LAN', 'Sesuai', NULL, NULL, '2025-11-03 20:41:48', '2025-11-03 20:41:48'),
(6, 8, 'ada', 'PLN', '4400', '43', 'ada', 'ada', 'Indihome', '900', 'Wireless', 'Sesuai', NULL, 'Kami ingin memiliki 2 LAB Komputer tetapi kendalanya pada Unit Komputer yang belum memadai untuk menciptakan 2 LAB Komputer. Dengan ini Kami Meminta Bantuan Berupa Unit Komputer.\r\nDan untuk pengisian pada sumber internet kami menggunakan 2 sumber, indihome dan starlink sementara untuk topologi jaringan kami menggunakan 2 Topologi, Lan dan Wireless.', '2025-11-03 23:12:32', '2025-11-05 16:49:42'),
(7, 101, 'ada', 'PLN', '16000', '70', 'ada', 'ada', 'Indihome', '100', 'LAN', 'Sesuai', '-', NULL, '2025-11-04 04:54:06', '2025-11-04 05:29:39'),
(8, 64, 'ada', 'PLN', '24', '25', 'ada', 'ada', 'Indihome', '50', 'LAN', 'Sesuai', NULL, 'Jika diperkenankan mohon bantuan PC karena PC yang ada berada pada spek bawah yaitu ram 2GB, kebutuhan sekarang minimal ram 4GB dengan proseccor Corel i5', '2025-11-04 06:09:51', '2025-11-10 12:53:25'),
(9, 3, 'ada', 'PLN', '24', '29', 'ada', 'ada', 'Indihome', '49', 'LAN', 'Sesuai', NULL, 'Perlu adanya perbaikan pada Ruang Lab. Komputer karna ruang Lab. Komputer yang dimiliki ukurannya tidak sesuai standar jumlah siswa yang ada serta  penambahan pada Komputer/PC clien dan komputer server  jumlah yang tersedia pada Lab Komputer untuk komputer clien 29 unit baik dan 7 unit rusak berat dan komputer server 1 unit baik 2 unit rusak berat', '2025-11-04 11:44:57', '2025-11-09 08:16:22'),
(10, 17, 'ada', 'PLN', '1', '8', 'ada', 'ada', 'Indihome', '50', 'LAN', 'Tidak Sesuai', 'Kecapatan yang dimiliki tidak mampu dalam memperluas jaringan sehingga terkadang menjadi penurunan kecepatan jaringan.', 'Lab komputer masih kekurangan perangkat komputer, perangkat jaringan, kecepatan jaringan, AC yang digunakan tidak cukup dengan kondisi Lab sehingga proses belajar terganggu serta perlengkapan untuk laboraturium komuter lainnya.', '2025-11-04 17:12:03', '2025-11-04 22:58:33'),
(11, 63, 'ada', 'PLN', '24', '35', 'tidak', 'ada', 'Indihome', '50', 'LAN', 'Sesuai', NULL, 'dibutuhkan perhatian penuh kepada sekolah swasta dari kemdikbudristek dalam pengembangan mutu sekolah', '2025-11-04 17:59:14', '2025-11-04 17:59:14'),
(12, 15, 'ada', 'PLN', '24', '22', 'ada', 'ada', 'Starlink', '150', 'Wireless', 'Sesuai', '-', '-', '2025-11-04 18:22:22', '2025-11-04 18:22:22'),
(13, 56, 'ada', 'PLN', '24', '66', 'ada', 'ada', 'Indihome', '20', 'LAN', 'Tidak Sesuai', 'Saat penggunaan bersama , jaringan terlalu  lambat', '1. Bantuan Jaringan Internet Untuk dapat diakses oleh peserta didik\r\n2. perbaikan bangunan/rehab berat Bangunan Laboratorium komputer karena sudah tidak aman di gunakan. \r\n3. Penambahan Komputer Client \r\n4. Penambahan Lab Multimedia., karena bangunan yang digunakan bukan  diperuntukan untuk lab tapi menggunakan bangunan kelas', '2025-11-04 18:23:45', '2025-11-04 18:24:59'),
(14, 1, 'ada', 'PLN', '24', '0', 'tidak', 'ada', 'Indihome', '0', NULL, 'Sesuai', 'Tidak Ada', '1. Bantuan TIK ( Croombuk,Leptop, Komputer, infokus dan Layar Infokus  )', '2025-11-04 21:09:31', '2025-11-04 21:09:31'),
(15, 88, 'ada', 'PLN', '12', '15', 'ada', 'ada', 'Starlink', '86', 'LAN', 'Sesuai', 'Dikerenakan Komputer/PC banyak yang rusak dan sekolah kekurangan sarana Komputer.', 'Kami dari pihak sekolah mohon bantuan dari bapak/Ibu untuk melihat hal ini. Dimana kurangnya fasilitas maupun sarana penunjang yang belum memadai (Jaringan Internet, Komputer, Server, Monitor). Kami mohon semoga kedepanya lebih diperhatikan lagi hal - hal yang menjadi faktor kurang tersedianya sarana penunjang tersebut. Demi kemajuan dan kelancaran sekolah kami.', '2025-11-04 23:47:31', '2025-11-04 23:47:31'),
(16, 97, 'ada', 'PLN', '24', NULL, 'ada', 'ada', 'Indihome', '150', 'LAN', 'Sesuai', NULL, 'Penambahan peralatan komputer', '2025-11-05 15:03:36', '2025-11-05 15:07:23'),
(17, 91, 'ada', 'PLN', '24', '25', 'ada', 'ada', 'Indihome', '50', 'Wireless', 'Sesuai', '-', 'mohon agar jaringan internet lebih baik kedepannya', '2025-11-05 19:06:00', '2025-11-05 19:06:00'),
(18, 5, 'ada', 'PLN', '12', '10', 'tidak', 'ada', 'Lainnya', '14', 'Wireless', 'Tidak Sesuai', 'Sekolah SMA Negeri 11 Buru menggunalan koneksi wifi berbayar per bulan ( menumpang oleh usaha wifi masyarakat )', 'Mohon kiranya agar pemerintah dalam hal ini pihak pengembang untuk memfasilitasi sekolah kami terkait dengan jaringan Internet serta pengadaan laptop sekolah agar dalam pelaksanaan yang terkait dengan hal ini bisa berjalan maksimal.', '2025-11-05 19:10:32', '2025-11-05 19:10:32'),
(19, 71, 'ada', 'PLN', '24', '4', 'ada', 'tidak', 'Indihome', '1200', 'Wireless', 'Tidak Sesuai', 'Jaringan lelet jika masuk ke aplikasi dapodik, rkas dll', 'Mohon bantuan internet sendiri dan penambahan komputer/PC 6 Unit', '2025-11-05 19:13:49', '2025-11-05 19:13:49'),
(20, 90, 'ada', 'PLN', '12', '20', 'tidak', 'ada', 'Lainnya', '10', 'Wireless', 'Sesuai', NULL, NULL, '2025-11-05 20:19:25', '2025-11-05 20:19:25'),
(21, 102, 'ada', 'PLN', '24', '15', 'ada', 'ada', 'Lainnya', '20', 'LAN', 'Sesuai', 'hingga saat ini sekolah kami belum pernah mendapatkan bantuan internet/kuota', 'Manambah Fasilitas pendukung seperti ruang belajar, ruang perpustakaan, ruang komputer. dan gedung-gedung lainnya karena sekolah kami masi menumpang sehingga kami terbatas dengan fasilitas', '2025-11-06 00:34:23', '2025-11-06 00:34:23'),
(22, 77, 'ada', 'PLN', '24', '65', 'ada', 'ada', 'Lainnya', '1', 'Wireless', 'Tidak Sesuai', 'kecapatan loding tidak maksimal lambat apabila kondidi angin atau hujan. lampu PLN sering padam. jumlah pengguna banyak', 'sekolah membutuhkan jaringan WIFI yang Mbps nya besar sehingga baik guru maupun siswa dapat maximal menggunakan untuk proses pembelajaran terutama saat menghadapi ujian Asesmen, TKA, SNBK. dan ujian ujian lain yang membutuhkan akses internet', '2025-11-06 03:39:03', '2025-11-06 03:39:03'),
(23, 76, 'ada', 'PLN', '24', '12', 'ada', 'ada', 'Starlink', '50', 'Wireless', 'Tidak Sesuai', 'Jika menggunakan Starlink maka kecepatan hanya terbatas pada 2 ruangan dengan jarak kecepatan hanya 50 meter, sehinggga kebutuhan yang digunakan oleh pendidik di setiap ruang lain belum memenuhi sesuai yang dibutuhkan dalam aktivitas.', '1.Berharap dari kami ada pemerataan Akses internet artinya mengalokasikan anggaran khusu untuk menambah infrastruktur internet pada sekolah yang berada di daerah 3 T, yang kurang terjangkau untuk dapat mengurangi kesenjangan digital.\r\n\r\n2.Berharap mengadakan pelatihan TIK secara berkelanjutan bagi guru dan tenaga kependidikan dalam pembelajaran.', '2025-11-06 04:34:37', '2025-11-06 04:34:37'),
(24, 92, 'ada', 'PLN', '24', '40', 'ada', 'ada', 'Starlink', '30', 'LAN', 'Sesuai', NULL, NULL, '2025-11-06 17:00:53', '2025-11-06 17:00:53'),
(25, 93, 'ada', 'PLN', '24', '42', 'ada', 'ada', 'Starlink', '120', 'Wireless', 'Tidak Sesuai', 'Perlu Penambahan Jaringan Internet Bakti Aksi', 'Perlua Bantuan Jaringan Internet Bakti Aksi guna memperlancar aktifitas Siswa dalam kegiatan proses belajar mengajar, terutama dalam pelaksanaan ulang secara Online', '2025-11-06 20:29:41', '2025-11-06 20:29:41'),
(26, 24, 'ada', 'PLN', '24', '40', 'ada', 'ada', 'Indihome', '300', 'LAN', 'Sesuai', 'Masih kurang banyak yang belum terjangkau', 'Penambahan Komputer', '2025-11-07 02:34:45', '2025-11-07 02:34:45'),
(27, 333, 'ada', 'PLN', '130', '36', 'ada', 'ada', 'Indihome', '80', 'LAN', 'Sesuai', '-', '-', '2025-11-07 11:17:56', '2025-11-07 11:17:56'),
(28, 297, 'ada', 'PLN', '24', '1', 'ada', 'ada', 'Lainnya', '10', 'Wireless', 'Sesuai', 'Tidak Ada', 'Perkembangan Kualitas PLN Maupun Internet', '2025-11-07 18:10:13', '2025-11-07 18:10:13'),
(29, 307, 'ada', 'PLN', '24', '22', 'ada', 'ada', 'Indihome', '100', 'LAN', 'Sesuai', 'Jumlah siswa terlalu banyak sehingga tidak memungkinkan untuk bisa login sekaligus dengan kapasitas internet yang tersedia sehingga perlu panambahan alat', 'perlu penambahan alat dan jaringan internet sehingga bisa menjangkau seluruh siswa karena dengan alat yang ada hanya mampu untuk mengakomodir internet untuk satu ruang belajar saja sedangkan di sekolah terdapat tujuh ruang belajar', '2025-11-07 18:31:33', '2025-11-07 18:31:33'),
(30, 279, 'ada', 'PLN', '24', '25', 'ada', 'ada', 'Indihome', '200', 'LAN', 'Sesuai', '-', 'Kiranya dapat memberikan bantuan Komputer karena jumlah siswa peserta Tes Kemampuan Akdemik (TKA) sangat banyak dan komputer tidak mencukupi...terima kasih', '2025-11-08 03:19:17', '2025-11-08 03:19:17'),
(31, 289, 'ada', 'PLN', '24', '30', 'ada', 'ada', 'Lainnya', '10', 'LAN', 'Tidak Sesuai', 'Jaringan tidak stabil', 'Bantuan alat penguat/penghasil jaringan internet yang benar-benar mampu mengatasi kendala selama ini', '2025-11-09 06:19:52', '2025-11-09 06:19:52'),
(32, 251, 'ada', 'PLN', '24', '32', 'ada', 'ada', 'Indihome', '100', 'LAN', 'Sesuai', NULL, NULL, '2025-11-09 15:23:20', '2025-11-09 15:23:20'),
(33, 89, 'ada', 'PLN', '24', '50', 'ada', 'ada', 'Indihome', '50', 'LAN', 'Tidak Sesuai', 'Kecepatanjumlah internet tidak sesuai dengan Bandwith yang di bayar', 'kalau bisa Pemerintah wajib memberikan saran kepada pihak penyedia Intenet (Telkomsel) untuk mrmberikan akses sesuai dengan kecepatan yang Internet yang setiap bulan di bayar sesuai kecepatan Bandwith tetapi kenyataan yang di bayar setiap sama seperti kecepatan internet 20 MBPS.  sehingga sangat diharapkan untuk memperhatika hal ini ini, karena sekolah sangat memerlukan akses internet yang lebih bersar.', '2025-11-09 16:48:48', '2025-11-09 16:48:48'),
(34, 80, 'ada', 'PLN', '24', '7', 'tidak', 'ada', 'Lainnya', '32', 'Wireless', 'Sesuai', 'Kondisi Listrik yang kadang tidak stabil', 'Pengadaan Ruang Komputer', '2025-11-09 17:05:06', '2025-11-09 17:05:06'),
(35, 440, 'ada', 'PLN', '13000', '40', 'ada', 'ada', 'Indihome', '100', 'LAN', 'Tidak Sesuai', 'TIDAK SESUAI DI SEBABKAN OLEH JUMLAH SISWA DAN LAB TIDAK BISA MENAMPUNG KECEPATAN TERSEBUT SERTA TIDAK BISA MENJANGKAU SEMUA RUANGAN YANG ADA DISEKOLAH', 'DIBUTUHKAN SARANA KOMPUTER UNTUK BISA MENAMPUNG BANYAK PESERTA DIDIK YANG PERSIAPAN UJIAN', '2025-11-09 17:35:10', '2025-11-09 19:47:35'),
(36, 269, 'ada', 'PLN', '16500', '40', 'ada', 'ada', 'Indihome', '50', 'LAN', 'Sesuai', 'Kebutuhan lebih dari Internet yang tersedia.', '1.  Penambahan Komputer/PC untuk Lab. Komputer Teknik Komputer dan Jaringan sebanyak 49 unit\r\n2. Penambahan Komputer/PC untuk Lab. Komputer Otomatisasi Tata Kelola Perkantoran sebanyak 20 unit\r\n3. Penambahan Komputer/PC untuk Lab. Komputer Akuntansi dan Keuangan Lembaga sebanyak 19 unit\r\n4. Penambahan Komputer/PC untuk Lab. Komputer Bisnis Daring dan Pemasaran sebanyak 22 unit\r\n5. Penambahan Komputer/PC untuk Lab. Komputer Perhotelan sebanyak 20 unit\r\n6. Pengadaan Komputer/PC untuk Perpustakaan sebanyak 3 unit\r\n7. Pengadaan Komputer/PC atau Laptop untuk Administrasi Ruang Wakasek sebanyak 10 unit \r\n8. Pengadaan Komputer/PC atau Laptop untuk Pengelolaan Administrasi Kantor sebanyak 7 unit\r\n9. Rehabilitasi Lab Komputer Teknik Komputer dan Jaringan dengan luas bangunan (12 x 8) M2\r\n10. Rehabilitasi Lab Komputer Otomatisasi Tata Kelola Perkantoran dengan luas bangunan (12 x 8) M2\r\n11. Rehabilitasi Lab Komputer Akuntansi dan Keuangan Lembaga dengan luas bangunan (12 x 8) M2\r\n12. Rehabilitasi Lab Komputer Bisnis Daring dan Pemasaran dengan luas bangunan (12 x 8) M2\r\n13 Rehabilitasi Lab Komputer Perhotelan dengan luas bangunan (12 x 8) M2\r\n14. Pengadaan Layanan Jaringan Internet berupa Starlink sebanyak 6 unit', '2025-11-09 18:11:44', '2025-11-11 19:00:40'),
(37, 272, 'ada', 'PLN', '24', '30', 'ada', 'ada', 'Indihome', '100', 'LAN', 'Tidak Sesuai', 'Pengguna banyak, namun Bandwidth belum mencukupi untuk semua warga sekolah.', 'Dapat diperhatikan dibagian insfrastruktur sekolah', '2025-11-09 18:48:39', '2025-11-09 18:48:39'),
(38, 243, 'ada', 'PLN', '7', '4', 'ada', 'ada', 'Indihome', '22', 'LAN', 'Tidak Sesuai', 'jaringan untuk menampung banyak akses user pada saat akif belajar mengajar', 'Untuk menunjang Pembelajaran yang lebih efisien dan profesional maka di perlukan dukungan peralatan fasilitas Komputer dan jaringan dengan spek yang memadai untuk proses Belajar mengajar Guru dan siswa dalam jangka panjang, DI Ruang Lab. Komputer SLB Negeri Langgur ada 4 Unit Komputer Rusak dan 9 Chromebook.\r\n\r\nDengan ini, saran kami untuk pengembangan kualitas pembelajaran perlunya dukungan fasilitas belajar mengajar sebagai berikut:\r\n1. 20 unit Komputer dengan Spek (Procesor intel Core i5, Ram 8gb, monitor 32 inch, mouse logitech, Keybord logitech, suport NVDIA)\r\n2. Bantuan Internet kualitas tinggi dengan luasan area 80 meter persegi.\r\n3. 10 Projector layar infokus', '2025-11-09 18:49:10', '2025-11-14 21:25:22'),
