(300, 306, NULL, NULL, NULL, '2025-10-26 10:55:23', '2025-10-26 10:55:23'),
(301, 307, NULL, NULL, NULL, '2025-10-26 10:55:24', '2025-10-26 10:55:24'),
(302, 308, '1. Sebelah selatan perbatasan dengan sekolah SD Negeri Telaga Nipa.\r\n2. sebelah utara perbatasan dengan tanah negara.\r\n3. sebelah barat berbatasan dengan tanah negara.\r\n4. sebelah barat berbatasan dengan tanah negara.', 'SMA N 9 SBB berada di daerah pesisir, penduduknya berasal dari sulawesi tenggara (Buton), kondisi sosial masyarakat, sangat menghargai perbadaan, dengan mata pencarian utama petani dan nelayan', '1. Tansportasi Laut\r\n2.Transportasi Darat', '2025-10-26 10:55:24', '2025-11-11 23:54:50'),
(303, 309, NULL, NULL, NULL, '2025-10-26 10:55:24', '2025-10-26 10:55:24'),
(304, 310, NULL, NULL, NULL, '2025-10-26 10:55:24', '2025-10-26 10:55:24'),
